def main():
    base_dir = os.path.dirname(os.path.abspath(__file__))
    icons_dir = os.path.join(base_dir, "icons")
    dark_dir = os.path.join(icons_dir, "dark")
    light_dir = os.path.join(icons_dir, "light")
    
    os.makedirs(dark_dir, exist_ok=True)
    os.makedirs(light_dir, exist_ok=True)
    
    for name, content in ICONS.items():
        # Dark theme icons should be white (#ffffff)
        dark_content = content.replace('stroke="currentColor"', 'stroke="#ffffff"')
        # Light theme icons should be dark grey (#1e293b)
        light_content = content.replace('stroke="currentColor"', 'stroke="#1e293b"')
        
        with open(os.path.join(dark_dir, f"{name}.svg"), "w", encoding="utf-8") as f:
            f.write(dark_content)
            
        with open(os.path.join(light_dir, f"{name}.svg"), "w", encoding="utf-8") as f:
            f.write(light_content)
            
        print(f"Generated {name}.svg for dark and light themes")

if __name__ == "__main__":
    main()
